// ── Render: Clients ──
// ── CRM ──

function renderCRM() {
  if (STATE.crm.detailId) return renderCrmDetail(STATE.crm.detailId);
  let html = '<div id="crm-content"><div style="text-align:center;padding:40px;color:var(--muted);">Chargement CRM...</div></div>';
  loadCrmData();
  return html;
}

async function loadCrmData() {
  if (STATE.crm.loading) return;
  STATE.crm.loading = true;
  try {
    const params = new URLSearchParams();
    if (STATE.crm.filter.status) params.set('status', STATE.crm.filter.status);
    if (STATE.crm.filter.search) params.set('search', STATE.crm.filter.search);
    const qs = params.toString();

    const [clientsRes, statsRes] = await Promise.all([
      api('/api/crm/clients' + (qs ? '?' + qs : '')),
      api('/api/crm/stats')
    ]);
    STATE.crm.clients = clientsRes.clients || [];
    STATE.crm.stats = statsRes;
    renderCrmContent();
  } catch(e) {
    const el = document.getElementById('crm-content');
    if (el) el.innerHTML = '<div style="color:var(--red);padding:20px;">Erreur CRM: ' + esc(e.message) + '</div>';
  } finally {
    STATE.crm.loading = false;
  }
}

function renderCrmContent() {
  const el = document.getElementById('crm-content');
  if (!el) return;
  const s = STATE.crm.stats || {};
  const clients = STATE.crm.clients;

  let html = '';

  // KPIs
  html += '<div class="kpi-grid" style="margin-bottom:20px;">';
  html += crmKpi(s.total || 0, 'Total', '--blue');
  html += crmKpi(s.actifs || 0, 'Actifs', '--green');
