function renderPipeline() {
  let html = '<div id="pipeline-content"><div style="text-align:center;padding:40px;color:var(--muted);">Chargement pipeline...</div></div>';
  loadPipelineData();
  return html;
}

async function loadPipelineData() {
  if (STATE.pipeline.loading) return;
  STATE.pipeline.loading = true;
  try {
    const res = await api('/api/crm/pipeline');
    STATE.pipeline.affaires = res.affaires || [];
    STATE.pipeline.stats = res.stats || {};
    renderPipelineContent();
  } catch(e) {
    const el = document.getElementById('pipeline-content');
    if (el) el.innerHTML = '<div style="color:var(--red);padding:20px;">Erreur pipeline: ' + esc(e.message) + '</div>';
  } finally {
    STATE.pipeline.loading = false;
  }
}

function renderPipelineContent() {
  const el = document.getElementById('pipeline-content');
  if (!el) return;
  const s = STATE.pipeline.stats;
  const affaires = STATE.pipeline.affaires;
  const phases = ['Lead', 'Qualifi\u00e9', 'Proposition', 'N\u00e9gociation', 'Gagn\u00e9', 'Production', 'Perdu'];
  const phaseClass = { 'Lead': 'phase-lead', 'Qualifi\u00e9': 'phase-qualifie', 'Proposition': 'phase-proposition', 'N\u00e9gociation': 'phase-negociation', 'Gagn\u00e9': 'phase-gagne', 'Production': 'phase-production', 'Perdu': 'phase-perdu' };
  const phaseColor = { 'Lead': '--blue', 'Qualifi\u00e9': '--cyan', 'Proposition': '--yellow', 'N\u00e9gociation': '--purple', 'Gagn\u00e9': '--green', 'Production': '--cyan', 'Perdu': '--red' };

  let html = '';

  // Summary cards
  html += '<div class="pipeline-summary">';
  html += pipelineSummaryCard(s.total || 0, 'Affaires', '--blue');
  html += pipelineSummaryCard(s.valeurTotale ? fmtEur(s.valeurTotale) : '0 \u20ac', 'Valeur totale (annuel)', '--text');
  html += pipelineSummaryCard(s.valeurPonderee ? fmtEur(s.valeurPonderee) : '0 \u20ac', 'Pond\u00e9r\u00e9 (prob.)', '--yellow');
  html += pipelineSummaryCard(s.caGagne ? fmtEur(s.caGagne) : '0 \u20ac', 'CA gagn\u00e9', '--green');
  html += '</div>';

  // Toolbar
  html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;">';
  html += '<span style="font-size:12px;color:var(--muted);">' + affaires.length + ' affaire' + (affaires.length > 1 ? 's' : '') + ' au total</span>';
  html += '<div style="display:flex;gap:8px;">';
  html += '<button class="btn btn-ghost btn-sm" style="font-size:11px;" onclick="exportCsv(\'pipeline\')">Export CSV</button>';
  html += '<button class="btn btn-ghost btn-sm" style="font-size:11px;" onclick="loadPipelineData()">Actualiser</button>';
  html += '<button class="btn btn-primary" onclick="openPipelineAffaireModal()">+ Nouvelle affaire</button>';
  html += '</div>';
  html += renderViewToggle('pipeline', { reload: 'renderPipelineContent()' });
  html += '</div>';

  const view = getView('pipeline');

  if (view === 'card') {
    // Card grid view
    html += '<div class="card-grid">';
    affaires.forEach(a => {
      const total = (a.montantOneshot || 0) + (a.montantRecurrent || 0) * 12;
      const prob = a.probabilite != null ? a.probabilite : 50;
      html += '<div class="entity-card" onclick="openPipelineAffaireModal(null,' + a.id + ')">';
      html += '<div class="entity-card-header"><div>';
      html += '<div class="entity-card-title">' + esc(a.nom) + '</div>';
      if (a.clientNom) html += '<div class="entity-card-subtitle">' + esc(a.clientNom) + (a.clientSociete ? ' \u2014 ' + esc(a.clientSociete) : '') + '</div>';
      html += '</div><span class="crm-badge ' + (phaseClass[a.phase] ? crmPipePhaseClass(a.phase) : '') + '" style="margin-left:auto;">' + esc(a.phase) + '</span></div>';
      html += '<div class="entity-card-body">';
      if (total > 0) html += '<div class="entity-card-row"><span class="entity-card-row-label">Valeur annuelle</span><span style="font-weight:700;color:var(--green);">' + fmtEur(total) + '</span></div>';
      if (a.montantRecurrent) html += '<div class="entity-card-row"><span class="entity-card-row-label">R\u00e9current</span><span style="color:var(--cyan);">' + fmtEur(a.montantRecurrent) + '/mois</span></div>';
      html += '<div class="entity-card-row"><span class="entity-card-row-label">Probabilit\u00e9</span><span>' + prob + '%</span></div>';
      if (a.typePrestation) html += '<div class="entity-card-row"><span class="entity-card-row-label">Type</span><span>' + esc(a.typePrestation) + '</span></div>';
      html += '</div></div>';
    });
    html += '</div>';
  } else if (view === 'liste') {
    // Table view
    html += '<div class="table-card"><table><thead><tr>';
    html += '<th>Affaire</th><th>Phase</th><th>Client</th><th>Type</th><th>Montant</th><th>R\u00e9current</th><th>Prob.</th><th></th>';
    html += '</tr></thead><tbody>';
    affaires.forEach(a => {
      const total = (a.montantOneshot || 0) + (a.montantRecurrent || 0) * 12;
      html += '<tr style="cursor:pointer;" onclick="openPipelineAffaireModal(null,' + a.id + ')">';
      html += '<td><strong>' + esc(a.nom) + '</strong></td>';
      html += '<td><span class="crm-badge ' + crmPipePhaseClass(a.phase) + '">' + esc(a.phase) + '</span></td>';
      html += '<td style="font-size:12px;">' + esc(a.clientNom || '--') + '</td>';
      html += '<td style="font-size:12px;">' + esc(a.typePrestation || '--') + '</td>';
      html += '<td style="font-size:12px;font-weight:600;">' + (total > 0 ? fmtEur(total) : '--') + '</td>';
      html += '<td style="font-size:12px;color:var(--cyan);">' + (a.montantRecurrent ? fmtEur(a.montantRecurrent) + '/m' : '--') + '</td>';
      html += '<td style="font-size:12px;">' + (a.probabilite != null ? a.probabilite + '%' : '--') + '</td>';
      html += '<td><button class="btn btn-ghost btn-sm" style="font-size:9px;padding:1px 5px;color:var(--red);" onclick="event.stopPropagation();deletePipelineAffaire(' + a.id + ')">X</button></td>';
      html += '</tr>';
    });
    html += '</tbody></table></div>';
  } else {
  // Kanban board (default for pipeline)
  html += '<div class="pipeline-board">';
  phases.forEach(phase => {
    const items = affaires.filter(a => a.phase === phase);
    const colTotal = items.reduce((s, a) => s + (a.montantOneshot || 0) + (a.montantRecurrent || 0) * 12, 0);
    html += '<div class="pipeline-col ' + (phaseClass[phase] || '') + '">';
    html += '<div class="pipeline-col-header">';
    html += '<span class="pipeline-col-title" style="color:var(' + (phaseColor[phase] || '--text') + ');">' + esc(phase) + '</span>';
    html += '<span class="pipeline-col-count">' + items.length + '</span>';
    html += '</div>';
    html += '<div class="pipeline-col-body">';
    if (items.length === 0) {
      html += '<div style="padding:20px 8px;text-align:center;color:var(--muted);font-size:11px;">Aucune affaire</div>';
    }
    items.forEach(a => {
      const total = (a.montantOneshot || 0) + (a.montantRecurrent || 0) * 12;
      const prob = a.probabilite != null ? a.probabilite : 50;
      const probColor = prob >= 70 ? '--green' : prob >= 40 ? '--yellow' : '--muted';
      html += '<div class="pipeline-card" onclick="openPipelineAffaireModal(null, ' + a.id + ')">';
      html += '<div class="pipeline-card-title">' + esc(a.nom) + '</div>';
      if (a.clientNom) {
        html += '<div class="pipeline-card-client">' + esc(a.clientNom) + (a.clientSociete ? ' \u2014 ' + esc(a.clientSociete) : '') + '</div>';
      }
      html += '<div style="display:flex;align-items:center;justify-content:space-between;">';
      html += '<span class="pipeline-card-amount">' + (total > 0 ? fmtEur(total) : '--') + '</span>';
      html += '<span class="pipeline-card-prob" style="background:rgba(255,255,255,0.05);color:var(' + probColor + ');">' + prob + '%</span>';
      html += '</div>';

